#!/usr/bin/env node
/**
 * Extracts only the Solar Linear icons used in the project from @iconify-json/solar
 * and generates a small TypeScript module with addIcon() calls.
 *
 * Usage: node scripts/generate-solar-icons.mjs
 *
 * The generated file is committed to the repo so builds don't need this script.
 * Re-run when adding new icons to the codebase.
 */

import { readFileSync, writeFileSync } from 'node:fs'
import { resolve, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = resolve(__dirname, '..')

// Load the full Solar icon set JSON — resolve through Node module resolution
import { createRequire } from 'node:module'
const require = createRequire(import.meta.url)
const solarJsonPath = require.resolve('@iconify-json/solar/icons.json')
const solarData = JSON.parse(readFileSync(solarJsonPath, 'utf-8'))

// Also load MDI for brand icons
const mdiJsonPath = require.resolve('@iconify-json/mdi/icons.json')
const mdiData = JSON.parse(readFileSync(mdiJsonPath, 'utf-8'))

// All Solar Linear icons used in the project (lucide -> solar mapping)
const ICON_NAMES = [
  'add-circle-linear',
  'alt-arrow-down-linear',
  'alt-arrow-left-linear',
  'alt-arrow-right-linear',
  'alt-arrow-up-linear',
  'arrow-left-linear',
  'arrow-right-linear',
  'arrow-right-up-linear',
  'bell-linear',
  'buildings-2-linear',
  'calendar-linear',
  'card-linear',
  'chart-2-linear',
  'check-circle-linear',
  'check-read-linear',
  'clipboard-check-linear',
  'clipboard-linear',
  'close-circle-linear',
  'cloud-linear',
  'code-linear',
  'copy-linear',
  'danger-circle-linear',
  'danger-triangle-linear',
  'dollar-minimalistic-linear',
  'document-text-linear',
  'double-alt-arrow-left-linear',
  'double-alt-arrow-right-linear',
  'download-linear',
  'eye-closed-linear',
  'eye-linear',
  'filter-linear',
  'folder-linear',
  'gallery-add-linear',
  'gallery-linear',
  'global-linear',
  'hamburger-menu-linear',
  'info-circle-linear',
  'infinity-linear',
  'link-linear',
  'lock-linear',
  'logout-3-linear',
  'magnifer-linear',
  'mention-circle-linear',
  'menu-dots-linear',
  'monitor-linear',
  'moon-linear',
  'plain-linear',
  'question-circle-linear',
  'record-circle-linear',
  'refresh-circle-linear',
  'scale-linear',
  'settings-linear',
  'share-linear',
  'shield-check-linear',
  'shield-linear',
  'sidebar-minimalistic-linear',
  'sort-from-bottom-to-top-linear',
  'sort-from-top-to-bottom-linear',
  'sort-vertical-linear',
  'square-arrow-right-up-linear',
  'sun-2-linear',
  'stopwatch-linear',
  'trash-bin-trash-linear',
  'graph-up-linear',
  'tuning-2-linear',
  'undo-left-round-linear',
  'upload-linear',
  'user-check-rounded-linear',
  'user-linear',
  'widget-2-linear',
  'bolt-linear',
  'menu-dots-square-linear',
  'letter-linear',
  'transfer-horizontal-linear',
]

// MDI brand icons used for social media links
const MDI_ICON_NAMES = [
  'twitter',
  'instagram',
  'facebook',
  'github',
  'youtube',
  'linkedin',
]

const defaultWidth = solarData.width || 24
const defaultHeight = solarData.height || 24

const missing = []
const entries = []

for (const name of ICON_NAMES) {
  const iconData = solarData.icons[name]
  if (!iconData) {
    missing.push(name)
    continue
  }
  const w = iconData.width || defaultWidth
  const h = iconData.height || defaultHeight
  entries.push(
    `  addIcon('solar:${name}', { body: '${iconData.body.replace(/'/g, "\\'")}', width: ${w}, height: ${h} })`,
  )
}

// Extract MDI brand icons
const mdiDefaultWidth = mdiData.width || 24
const mdiDefaultHeight = mdiData.height || 24

for (const name of MDI_ICON_NAMES) {
  const iconData = mdiData.icons[name]
  if (!iconData) {
    missing.push(`mdi:${name}`)
    continue
  }
  const w = iconData.width || mdiDefaultWidth
  const h = iconData.height || mdiDefaultHeight
  entries.push(
    `  addIcon('mdi:${name}', { body: '${iconData.body.replace(/'/g, "\\'")}', width: ${w}, height: ${h} })`,
  )
}

if (missing.length > 0) {
  console.error('Missing icons:', missing)
  process.exit(1)
}

const output = `/**
 * AUTO-GENERATED by scripts/generate-solar-icons.mjs — do not edit manually.
 * Contains only the Solar Linear icons used in this project (~${entries.length} icons).
 * Re-run: node scripts/generate-solar-icons.mjs
 */
import { addIcon } from '@iconify/react'

export function registerSolarIcons(): void {
${entries.join('\n')}
}
`

const outPath = resolve(ROOT, 'apps/web/src/lib/solar-icons.generated.ts')
writeFileSync(outPath, output, 'utf-8')

const sizeKB = (Buffer.byteLength(output, 'utf-8') / 1024).toFixed(1)
console.log(`Generated ${outPath} (${entries.length} icons, ${sizeKB} KB)`)
